INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-02411', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '健康照護之財務負擔是籌措財源常被關心的議題，關於平等主義與自由主義之立場界定，下列何者敘述 錯誤？', '["平等主義認為維繫民眾健康是政府責任，所有公民都應享有基本健康照護，故財源籌措應採量能原則， 以達社會互助與所得重分配的效果", "自由主義對於健康照護的需求，視為社會對個人才智與努力程度下的報酬，較從個人的公平性出發， 講求受益原則", "採全民健康照護的國家較強調個人公平、財源籌措主要採取受益原則", "採全民健康照護的國家較強調社會公平、財源籌措主要採取量能原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02412', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於社會保險及量能原則之敘述，何者錯誤？', '["量能原則係指衡量保險對象的經濟負擔能力，再決定其分攤的費用", "量能原則的垂直公平指保險對象負擔的費用與其經濟負擔能力呈正相關、水平公平是指經濟負擔能力 相同者，應負擔相同的費用，不因職業類別或眷口數多寡而有不同", "社會保險對於無法預期風險事故的發生及有相同風險的一群人，依量能原則強制由參與風險分擔團體 成員來共同分擔", "社會保險制度強調個人公平性，財源籌措上採取受益原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02413', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會福利制度所指涉的「給付行政」應採取「法律保留」與「依法行政」的說明，下列何者錯誤？', '["社會福利行政實施事項必須有法律授權依據，於法治國家之行政權的形式，必須依據法律之規定為之", "社會福利之社會給付涉及人民生活保障及社會資源公平使用的重要問題，因此應經立法程序的民主討論", "社會給付的來源，無論是社會保險費或稅收，常伴隨干預行政或他人之負擔，「法律保留」與「依法 行政」原則可防止社會行政的恣意與擅斷", "現代民主國家社會福利理念，主要是慈善救濟的基本精神，所以必須透過法律定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02414', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會救助法所列之急難救助乙項，下列何者無法適用？', '["主要家計負責人失蹤致生活陷於困境", "戶內人口死亡無力殮葬", "財產或存款帳戶因遭強制執行、凍結或其他原因未能即時運用，致生活陷於困境", "欠缺車資返鄉未設籍之外國人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02415', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於我國所實施的「家庭暴力防治法」，下列敘述何者正確？', '["所規定的家庭成員包括現有或曾為六等親以內之旁系血親或姻親", "要求主管機關每四年必須針對家庭暴力的問題及需求進行調查分析", "法院核發通常保護令得不經審理程序", "當事人可調解或和解保護令事件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02416', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於協助家暴目睹兒之觀點及作法，下列何者敘述錯誤？', '["從小目睹父母暴力相向，長大可能複製暴力，形成代間循環", "目睹家暴對兒童造成的間接傷害不亞於兒童虐待，都需要輔導協助", "目前無法透過家庭暴力防治法為目睹家庭暴力之兒少申請保護令", "教育人員知悉目睹家庭暴力兒童事件可撥打婦幼保護專線尋求協助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02417', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '請問何者並非普及式福利的優點？', '["個人尊嚴", "烙印效果", "人人平等", "社會團結"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02418', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '政府提供「扶養親屬寬減額」的性質屬於提莫斯（Richard Titmuss）所稱之何類型福利？', '["職業福利", "公共福利", "社區福利", "財稅福利"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02419', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據身心障礙者權利公約施行法，行政院為推動該公約相關工作，應邀集學者專家、身心障礙團體（機 構）及各政府機關代表，成立身心障礙者權益推動小組，該小組成員的設置比例，下列何者正確？', '["學者專家、身心障礙團體（機構）之人數不得少於總數1/2；任一性別不得少於1/3", "學者專家、身心障礙團體（機構）之人數不得少於總數1/3；任一性別不得少於1/2", "學者專家、身心障礙團體（機構）之人數不得少於總數2/3；任一性別不得少於1/2", "學者專家、身心障礙團體（機構）之人數不得少於總數1/2；任一性別不得少於2/3"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02420', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者並非實物給付（in-kind）的提供形式？', '["老人送餐服務", "早期療育社區巡迴車", "低收入戶優先承租國民住宅", "特別照顧津貼"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02421', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於福利輸送的方式，有選擇式或普及式的福利，下列何者為選擇式福利的優點？', '["行政成本較低", "可以部分達到所得重新分配", "強調公民權利", "社會正當性不強"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02422', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', 'ICF為國際健康功能與身心障礙分類系統（International Classification of Functioning, Disability and Health） 的簡稱，我國於民國101年正式施行，ICF的主張及特色不包括？', '["超越醫療化障礙觀點", "身心障礙分類由舊制八大類擴大為十六大類", "人所處的情境會影響或限制其功能表現", "重視身心障礙者個別需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02423', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '在 Esping-Andersen（1990）「資本主義三個世界」之著作中，下列那一種福利體制採取的方式是以迫使 福利依賴者進入勞動力市場，以作為活化勞動力市場的政策？', '["自由主義模式", "社會民主主義模式", "統合主義模式", "東亞福利模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
